public class ShippingInfo
{
    public string Name { get; set; } = "";
    public string Address { get; set; } = "";
    public string City { get; set; } = "";
    public string ZipCode { get; set; } = "";
}

public class PaymentInfo
{
    public string CardNumber { get; set; } = "";
    public string ExpiryDate { get; set; } = "";
}

public class Order
{
    public ShippingInfo Shipping { get; set; } = new();
    public PaymentInfo Payment { get; set; } = new();
}

public interface IAddressValidator
{
    Task<bool> ValidateAddressAsync(string address, string city, string zip, CancellationToken ct);
}

@* CheckoutWizard.razor — manages active step and holds order state *@

<div class="checkout-wizard">
    <h2>Checkout</h2>

    <div class="wizard-progress">
        <span class="@StepClass(1)">1. Shipping</span>
        <span class="@StepClass(2)">2. Payment</span>
    </div>

    @if (_currentStep == 1)
    {
        <ShippingStep Shipping="_order.Shipping" OnNext="HandleShippingComplete" />
    }
    else if (_currentStep == 2)
    {
        <PaymentStep Payment="_order.Payment"
                     OnBack="HandleBack"
                     OnPlaceOrder="HandlePlaceOrder" />
    }
</div>

@code {
    /// <summary>
    /// Fired when the user clicks "Place Order" on the final step,
    /// delivering the completed order to the parent component.
    /// </summary>
    [Parameter]
    public EventCallback<Order> OnOrderPlaced { get; set; }

    private readonly Order _order = new();
    private int _currentStep = 1;

    private void HandleShippingComplete()
    {
        _currentStep = 2;
    }

    private void HandleBack()
    {
        _currentStep = 1;
    }

    private async Task HandlePlaceOrder()
    {
        await OnOrderPlaced.InvokeAsync(_order);
    }

    private string StepClass(int step) =>
        step == _currentStep ? "step active" :
        step < _currentStep  ? "step completed" :
                                "step";
}

@* ShippingStep.razor — collects shipping fields with async address validation *@
@implements IDisposable
@inject IAddressValidator AddressValidator

<fieldset disabled="@_isValidating">
    <legend>Shipping Information</legend>

    <div class="form-group">
        <label for="name">Full Name</label>
        <input id="name" @bind="Shipping.Name" @bind:event="oninput" />
    </div>

    <div class="form-group">
        <label for="address">Address</label>
        <input id="address" @bind="Shipping.Address" @bind:event="oninput"
               @oninput="ClearValidationError" />
    </div>

    <div class="form-group">
        <label for="city">City</label>
        <input id="city" @bind="Shipping.City" @bind:event="oninput"
               @oninput="ClearValidationError" />
    </div>

    <div class="form-group">
        <label for="zip">Zip Code</label>
        <input id="zip" @bind="Shipping.ZipCode" @bind:event="oninput"
               @oninput="ClearValidationError" />
    </div>
</fieldset>

@if (!string.IsNullOrEmpty(_errorMessage))
{
    <div class="validation-error" role="alert">@_errorMessage</div>
}

<div class="wizard-buttons">
    <button type="button"
            disabled="@_isValidating"
            @onclick="HandleNext">
        @if (_isValidating)
        {
            <span class="spinner" aria-hidden="true"></span>
            <span>Validating…</span>
        }
        else
        {
            <span>Next</span>
        }
    </button>
</div>

@code {
    [Parameter, EditorRequired]
    public ShippingInfo Shipping { get; set; } = default!;

    [Parameter]
    public EventCallback OnNext { get; set; }

    private bool _isValidating;
    private string? _errorMessage;

    // Cancels any in-flight validation when:
    //  - the user clicks Next again (re-validation)
    //  - the component is disposed (navigation away)
    private CancellationTokenSource? _validationCts;

    private void ClearValidationError(ChangeEventArgs _)
    {
        _errorMessage = null;
    }

    private async Task HandleNext()
    {
        _errorMessage = null;

        if (string.IsNullOrWhiteSpace(Shipping.Name)
            || string.IsNullOrWhiteSpace(Shipping.Address)
            || string.IsNullOrWhiteSpace(Shipping.City)
            || string.IsNullOrWhiteSpace(Shipping.ZipCode))
        {
            _errorMessage = "All shipping fields are required.";
            return;
        }

        // Cancel any previous in-flight validation before starting a new one.
        CancelPendingValidation();
        _validationCts = new CancellationTokenSource();
        var token = _validationCts.Token;

        _isValidating = true;

        try
        {
            var isValid = await AddressValidator.ValidateAddressAsync(
                Shipping.Address, Shipping.City, Shipping.ZipCode, token);

            // If cancelled between await and here, bail out.
            token.ThrowIfCancellationRequested();

            if (isValid)
            {
                await OnNext.InvokeAsync();
            }
            else
            {
                _errorMessage = "The address could not be verified. Please check and try again.";
            }
        }
        catch (OperationCanceledException)
        {
            // Validation was cancelled — either by a new attempt or disposal. No-op.
        }
        finally
        {
            // Only reset the spinner if this is still the active validation.
            if (_validationCts?.Token == token)
            {
                _isValidating = false;
            }
        }
    }

    private void CancelPendingValidation()
    {
        _validationCts?.Cancel();
        _validationCts?.Dispose();
        _validationCts = null;
    }

    public void Dispose()
    {
        CancelPendingValidation();
    }
}

