        <input id="card" @bind="Payment.CardNumber" @bind:event="oninput" />
    </div>

    <div class="form-group">
        <label for="expiry">Expiry Date</label>
        <input id="expiry" placeholder="MM/YY"
               @bind="Payment.ExpiryDate" @bind:event="oninput" />
